INSERT INTO public.lessons (id, module_id, title, content, video_url, estimated_duration_min, order_index, created_at, updated_at) VALUES
('30000000-0000-0000-0000-000000000001', '20000000-0000-0000-0000-000000000001', 'Python Nedir?', 'Python; okunabilirliği yüksek, çok amaçlı bir programlama dilidir.', 'https://example.com/lessons/python-nedir', 20, 1, '2026-05-15 10:03:00', '2026-05-15 10:03:00'),
