('50000000-0000-0000-0000-000000000001', '40000000-0000-0000-0000-000000000001', 'MULTIPLE_CHOICE', 'Python hangi tür bir dildir?', '[{"id": "A", "text": "Yüksek seviyeli, yorumlanan ve çok amaçlı bir programlama dili", "is_correct": true}, {"id": "B", "text": "Yalnızca makine koduna doğrudan yazılan düşük seviyeli dil", "is_correct": false}, {"id": "C", "text": "İşaretleme (markup) dili", "is_correct": false}, {"id": "D", "text": "Yalnızca veritabanı şeması tanımlayan deklaratif dil", "is_correct": false}]'::jsonb, 1, '2026-05-15 10:05:00', '2026-05-15 10:05:00'),
('50000000-0000-0000-0000-000000000002', '40000000-0000-0000-0000-000000000001', 'MULTIPLE_CHOICE', 'Python dosya uzantısı hangisidir?', '[{"id": "A", "text": ".py", "is_correct": true}, {"id": "B", "text": ".java", "is_correct": false}, {"id": "C", "text": ".exe", "is_correct": false}, {"id": "D", "text": ".html", "is_correct": false}]'::jsonb, 2, '2026-05-15 10:05:00', '2026-05-15 10:05:00'),
