('50000000-0000-0000-0000-000000000004', '40000000-0000-0000-0000-000000000001', 'MULTI_SELECT', 'Python hangi alanlarda kullanılabilir?', '[{"id": "A", "text": "Web geliştirme ve otomasyon", "is_correct": true}, {"id": "B", "text": "Yalnızca BIOS ayarları", "is_correct": false}, {"id": "C", "text": "Veri bilimi ve yapay zeka", "is_correct": true}, {"id": "D", "text": "Yalnızca yazıcı sürücüsü yazımı", "is_correct": false}]'::jsonb, 4, '2026-05-15 10:05:00', '2026-05-15 10:05:00'),
('50000000-0000-0000-0000-000000000005', '40000000-0000-0000-0000-000000000001', 'MULTIPLE_CHOICE', 'print fonksiyonu ne için kullanılır?', '[{"id": "A", "text": "Çıktıyı konsola veya standart çıktıya yazdırmak", "is_correct": true}, {"id": "B", "text": "Dosyayı silmek", "is_correct": false}, {"id": "C", "text": "Modül içe aktarmak", "is_correct": false}, {"id": "D", "text": "Hata ayıklayıcıyı kapatmak", "is_correct": false}]'::jsonb, 5, '2026-05-15 10:05:00', '2026-05-15 10:05:00'),
('50000000-0000-0000-0000-000000000006', '40000000-0000-0000-0000-000000000001', 'TRUE_FALSE', 'Python yalnızca mobil uygulama geliştirmek için kullanılır.', '[{"id": "A", "text": "İfade doğrudur", "is_correct": false}, {"id": "B", "text": "İfade yanlıştır", "is_correct": true}, {"id": "C", "text": "—", "is_correct": false}, {"id": "D", "text": "—", "is_correct": false}]'::jsonb, 6, '2026-05-15 10:05:00', '2026-05-15 10:05:00'),
