('50000000-0000-0000-0000-000000000008', '40000000-0000-0000-0000-000000000001', 'MULTIPLE_CHOICE', 'PEP 8 ne ile ilgilidir?', '[{"id": "A", "text": "Python kod stili ve biçimlendirme önerileri", "is_correct": true}, {"id": "B", "text": "Paket yükleme protokolü", "is_correct": false}, {"id": "C", "text": "Sanal ortam klasör adı", "is_correct": false}, {"id": "D", "text": "Veritabanı bağlantı dizesi biçimi", "is_correct": false}]'::jsonb, 8, '2026-05-15 10:05:00', '2026-05-15 10:05:00'),
